    "Margaret S. Odell": "325, 327\n9:23-24\n314\n11:1-11\n331\n11:7\n322\n12:8\n262\n12:9\n390\n14:44\n422\n14:47\n331\n16:11\n429\n17:15\n429\n17:34-37\n237\n17:41-47\n473\n18:41-47\n475\n19:4\n165\n21:7\n425\n21:8\n425\n20:18\n479\n20:25\n479\n20:27\n479\n20:31\n468\n22:16\n422\n25:1\n317\n25:7\n196, 479\n25:15\n196\n25:31\n196\n25:39\n280\n26:1\n513",
